// Helper: normalize string "null" / empty / undefined to actual null
const norm = (v) => {
  if (v === null || v === undefined) return null;
  if (typeof v !== 'string') return v;
  const t = v.trim().toLowerCase();
  if (t === '' || t === 'null' || t === 'undefined' || t === 'n/a' || t === 'none') return null;
  return v;
};

const body = $input.item.json.body || $input.item.json;
const msg = body.message || body;

const eventType = msg.type || '';
if (eventType && eventType !== 'end-of-call-report') {
  return [{ json: { skip: true, reason: 'not end-of-call event: ' + eventType } }];
}

const call = msg.call || {};
const customer = call.customer || {};
const analysis = msg.analysis || {};
const structured = analysis.structuredData || {};

const callId = call.id || msg.callId || '';
const customerPhone = customer.number || msg.customer?.number || '';
const customerName = customer.name || msg.customer?.name || '';

const callMetadata = call.metadata || msg.metadata || {};
const webSource = callMetadata.source || '';
const SOFIA_ID = 'a91daf92-a477-46ed-b4cf-3e8df3a92699';
const RILEY_ID = '6e9f5b0d-bb8b-4409-974a-557f78f62172';

const assistantId = call.assistantId 
  || msg.assistantId 
  || msg.assistant?.id 
  || call.assistant?.id 
  || '';

const artifact = msg.artifact || call.artifact || {};
const messages = artifact.messagesOpenAIFormatted || artifact.messages || msg.messages || [];

const lastFew = (Array.isArray(messages) ? messages : []).slice(-5);
const recentText = lastFew.map(m => (m.content || m.message || '')).join(' ').toLowerCase();
const transcriptLower = (msg.transcript || '').toLowerCase();

// Language is determined ONLY by which assistant handled the call.
// Sofia (SOFIA_ID) = Spanish. Everyone else = English.
// The previous hasSpanishContent keyword check was causing false positives:
// Riley's own system prompt and handoff phrases contain 'en español',
// which caused English calls to be misclassified as Spanish.
let language = 'en';
if (assistantId === SOFIA_ID) {
  language = 'es';
}

const webPage = callMetadata.page || '';
const isWebCall = webSource.startsWith('website_');
const startedAt = call.startedAt || msg.startedAt || null;
const endedAt = call.endedAt || msg.endedAt || null;
const endedReason = call.endedReason || msg.endedReason || '';
const durationSec = Math.round(msg.durationSeconds || (startedAt && endedAt ? (new Date(endedAt) - new Date(startedAt)) / 1000 : 0));
const transcript = msg.transcript || analysis.transcript || '';
const summary = analysis.summary || msg.summary || '';
const recordingUrl = msg.recordingUrl || call.recordingUrl || '';
const successEval = analysis.successEvaluation || '';
const cost = msg.cost || 0;

const noAnswerReasons = ['no-answer','busy','failed','customer-did-not-answer','voicemail','customer-busy','customer-ended-call-quickly'];
const wasAnswered = !noAnswerReasons.some(r => endedReason.toLowerCase().includes(r)) && durationSec > 10;

let normalizedPhone = (customerPhone || '').trim();
if (normalizedPhone && !normalizedPhone.startsWith('+')) {
  const digits = normalizedPhone.replace(/\D/g,'');
  normalizedPhone = digits.length === 10 ? '+1' + digits : '+' + digits;
}
if (!normalizedPhone && isWebCall) {
  normalizedPhone = 'web:' + callId.slice(0, 12);
}

const extracted = {
  business_name: norm(structured.business_name || structured.businessName),
  industry: norm(structured.industry),
  pain_point: norm(structured.pain_point || structured.painPoint),
  service_interest: norm(structured.service_interest || structured.serviceInterest),
  budget: norm(structured.budget),
  timeline: norm(structured.timeline),
  num_locations: norm(structured.num_locations || structured.locations),
  weekly_missed: norm(structured.weekly_missed || structured.weeklyMissed),
  current_setup: norm(structured.current_setup || structured.currentSetup),
  booked: structured.booked === true || structured.booked === 'true',
  qualified: structured.qualified === true || structured.qualified === 'true',
  escalate: structured.escalate === true || structured.escalate === 'true',
  escalate_reason: norm(structured.escalate_reason || structured.escalateReason) || '',
  sentiment: norm(structured.sentiment || analysis.sentiment) || 'neutral',
  next_action: norm(structured.next_action || structured.nextAction) || ''
};

return [{ json: {
  skip: false,
  callId,
  customerPhone: normalizedPhone,
  customerName,
  firstName: (customerName || '').split(' ')[0] || '',
  startedAt,
  endedAt,
  endedReason,
  durationSec,
  transcript,
  summary,
  recordingUrl,
  successEval,
  cost,
  wasAnswered,
  extracted,
  isWebCall,
  webSource,
  webPage,
  assistantId,
  language
} }];

const callData = $('Parse Vapi Payload').item.json;
const isAnonymousWeb = callData.isWebCall && callData.customerPhone.startsWith('web:');
const contactsArr = $input.item.json;
const existingContact = (Array.isArray(contactsArr) && contactsArr.length > 0) ? contactsArr[0] : null;
const ex = callData.extracted;

let urgency = 'warm';
if (ex.booked) { urgency = 'hot'; }
else if (ex.qualified) { urgency = 'hot'; }
else if (ex.escalate) { urgency = 'hot'; }
else if (!callData.wasAnswered) { urgency = existingContact?.urgency || 'warm'; }
else if (ex.sentiment === 'negative') { urgency = 'cold'; }

let leadStatus = 'contacted';
if (ex.booked) { leadStatus = 'demo_scheduled'; }
else if (ex.qualified) { leadStatus = 'qualified'; }
else if (!callData.wasAnswered) { leadStatus = 'attempted'; }
else if (ex.sentiment === 'negative' || ex.next_action === 'dead') { leadStatus = 'dead'; }
else { leadStatus = 'contacted'; }

const contactUpdate = {
  urgency,
  lead_status: leadStatus,
  last_call_at: callData.endedAt || new Date().toISOString(),
  last_call: callData.endedAt || new Date().toISOString(),
  call_count: (existingContact?.call_count || 0) + 1,
  updated_at: new Date().toISOString()
};
if (callData.customerName)  contactUpdate.name = callData.customerName;
if (ex.business_name)       contactUpdate.business_name = ex.business_name;
if (ex.industry)            contactUpdate.industry = ex.industry;
if (ex.pain_point)          contactUpdate.pain_point = ex.pain_point;
if (ex.service_interest)    contactUpdate.service_interest = ex.service_interest;
if (ex.budget)              contactUpdate.budget = ex.budget;
if (ex.timeline)            contactUpdate.timeline = ex.timeline;
if (callData.language)      contactUpdate.language = callData.language;

let branch = 'nurture';
if (!callData.wasAnswered)              branch = 'no_answer';
else if (ex.booked)                     branch = 'booked';
else if (ex.escalate)                   branch = 'escalate';
else if (ex.qualified)                  branch = 'qualified_no_book';
else if (leadStatus === 'dead')         branch = 'dead';
else                                     branch = 'nurture';

return [{ json: {
  ...callData,
  existingContact,
  contactExists: !!existingContact,
  contactUpdate,
  branch,
  urgency,
  leadStatus
} }];

