const data = $input.item.json;
const phone = data.customerPhone || '';
if (!phone || phone.startsWith('web:') || phone.startsWith('unknown')) {
  console.log('[Phone Guard] Skipping SMS — web call or no phone:', phone);
  return [];
}
const digits = phone.replace(/\D/g, '');
if (digits.length < 10) {
  console.log('[Phone Guard] Skipping SMS — invalid phone:', phone);
